import React, { useState, useEffect } from 'react';
import EnhancedChat from './components/EnhancedChat';
import ChatList from './components/ChatList';
import { NotificationSystem, useNotifications } from './components/NotificationSystem';
import { WalletModal } from './components/WalletModal';
import { VideoChat } from './components/VideoChat';
import { ProfilesPage } from './pages/ProfilesPage';
import { SettingsPage } from './pages/SettingsPage';
import Registration from './components/Auth/Registration';
import { MessageCircle, Heart, Settings, Users, Wallet, LogIn } from 'lucide-react';
import { initTelegramWebApp, isTelegramWebApp } from './services/telegramService';
import './styles/animations.css';

function App() {
 // State principal
 const [currentPage, setCurrentPage] = useState('welcome');
 const [showWallet, setShowWallet] = useState(false);
 const [showVideoChat, setShowVideoChat] = useState(false);
 const [balance, setBalance] = useState(1000);
 const [activeUsers, setActiveUsers] = useState(245);
 const [isLoggedIn, setIsLoggedIn] = useState(false);
 const [user, setUser] = useState(null);
 const [telegramWebApp, setTelegramWebApp] = useState(null);
 const { notify } = useNotifications();

 // Inițializare Telegram WebApp
 useEffect(() => {
   if (isTelegramWebApp()) {
     const tg = initTelegramWebApp();
     setTelegramWebApp(tg);
     
     // Verifică dacă userul este deja autentificat în Telegram
     if (tg.initDataUnsafe?.user) {
       const telegramUser = tg.initDataUnsafe.user;
       setUser({
         id: telegramUser.id.toString(),
         name: telegramUser.first_name,
         username: telegramUser.username,
         isTelegram: true
       });
       setIsLoggedIn(true);
     }
   }
 }, []);

 // WebSocket connection
 useEffect(() => {
   const ws = new WebSocket('ws://localhost:3001');

   ws.onopen = () => {
     console.log('Connected to server');
   };

   ws.onmessage = (event) => {
     const data = JSON.parse(event.data);
     switch (data.type) {
       case 'connection_established':
         setBalance(data.credits);
         break;
       case 'credits_updated':
         setBalance(data.credits);
         break;
       // Adaugă alte cazuri după necesitate
     }
   };

   return () => {
     ws.close();
   };
 }, []);

 // Verifică autentificarea când se schimbă pagina
 useEffect(() => {
   if (!isLoggedIn && !['welcome', 'register'].includes(currentPage)) {
     setCurrentPage('welcome');
     notify({
       type: 'error',
       title: 'Acces restricționat',
       message: 'Te rugăm să te înregistrezi pentru a accesa această secțiune'
     });
   }
 }, [currentPage, isLoggedIn, notify]);

 // Navigare
 const navigationItems = [
   { id: 'profiles', icon: Heart, label: 'Profiles', requiresAuth: true },
   { id: 'chat', icon: MessageCircle, label: 'Chat', requiresAuth: true },
   { id: 'settings', icon: Settings, label: 'Settings', requiresAuth: true }
 ];

 // Welcome Screen
 const WelcomeScreen = () => (
   <div className="h-full flex items-center justify-center">
     <div className="max-w-lg text-center p-8">
       <h1 className="text-4xl font-bold mb-4">Bine ai venit pe TerriMatch</h1>
       <p className="text-gray-600 mb-8">
         Platformă de dating și servicii personalizate
       </p>
       <button
         onClick={() => setCurrentPage('register')}
         className="px-8 py-3 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors"
       >
         Înregistrează-te pentru a începe
       </button>
     </div>
   </div>
 );

 // Handlers
 const handleAddCoins = (amount) => {
   if (!isLoggedIn) {
     notify({
       type: 'error',
       title: 'Acces restricționat',
       message: 'Te rugăm să te înregistrezi mai întâi'
     });
     return;
   }
   setBalance(prev => prev + amount);
   notify({
     type: 'success',
     title: 'TerriCoin adăugat',
     message: `Ai primit ${amount} TerriCoin!`
   });
 };

 const handleVideoCall = () => {
   if (!isLoggedIn) {
     notify({
       type: 'error',
       title: 'Acces restricționat',
       message: 'Te rugăm să te înregistrezi mai întâi'
     });
     return;
   }
   
   if (balance < 50) {
     notify({
       type: 'error',
       title: 'Fonduri insuficiente',
       message: 'Ai nevoie de minim 50 TC pentru un apel video'
     });
     return;
   }
   setShowVideoChat(true);
 };

 const handleMatch = (matchData) => {
   if (!isLoggedIn) {
     notify({
       type: 'error',
       title: 'Acces restricționat',
       message: 'Te rugăm să te înregistrezi mai întâi'
     });
     return;
   }
   
   notify({
     type: 'match',
     title: 'New Match!',
     message: `Ai un nou match cu ${matchData.name}!`
   });
 };

 const handleRegistrationSuccess = async (userData) => {
   // Înregistrare prin Telegram dacă este disponibil
   if (telegramWebApp && telegramWebApp.initDataUnsafe?.user) {
     userData = {
       ...userData,
       telegramId: telegramWebApp.initDataUnsafe.user.id,
       username: telegramWebApp.initDataUnsafe.user.username
     };
   }

   setUser(userData);
   setIsLoggedIn(true);
   setCurrentPage('profiles');
   notify({
     type: 'success',
     title: 'Bine ai venit!',
     message: 'Înregistrarea a fost realizată cu succes!'
   });

   // Închide WebApp-ul Telegram dacă este necesar
   if (telegramWebApp) {
     // telegramWebApp.close();
   }
 };

 // ... restul codului rămâne la fel

 return (
   <div className="min-h-screen bg-gray-50">
     {/* ... restul codului rămâne la fel ... */}
   </div>
 );
}

export default App;
